const fs = require("fs");
const path = require("path");

const rootDir = process.cwd();
const readmePath = path.join(rootDir, "README.md");

// Paths to the coverage summary files generated by Jest
const frontendSummaryPath = path.join(
   rootDir,
   "frontend/coverage/coverage-summary.json",
);
const backendSummaryPath = path.join(
   rootDir,
   "backend/coverage/coverage-summary.json",
);

function getCoverage(summaryPath, name) {
   if (!fs.existsSync(summaryPath)) {
      return `| ${name} | N/A | N/A | N/A | N/A |`;
   }
   const summary = require(summaryPath);
   const { lines, statements, functions, branches } =
      summary.total;
   return `| ${name} | ${lines.pct}% | ${statements.pct}% | ${functions.pct}% | ${branches.pct}% |`;
}

const frontendRow = getCoverage(
   frontendSummaryPath,
   "Frontend",
);
const backendRow = getCoverage(
   backendSummaryPath,
   "Backend",
);

const table = `
| Project | Lines | Statements | Functions | Branches |
| :--- | :---: | :---: | :---: | :---: |
${frontendRow}
${backendRow}
`;

let readmeContent = fs.readFileSync(readmePath, "utf8");
const startMarker = "<!-- COVERAGE-START -->";
const endMarker = "<!-- COVERAGE-END -->";

const startIndex = readmeContent.indexOf(startMarker);
const endIndex = readmeContent.indexOf(endMarker);

const before = readmeContent.substring(
   0,
   startIndex + startMarker.length,
);
const after = readmeContent.substring(endIndex);
const newContent = `${before}\n${table}\n${after}`;
fs.writeFileSync(readmePath, newContent);

console.log("README.md updated with coverage report.");
